import json
import os
from pathlib import Path

class ConfigLoader:
    def __init__(self):
        # All logic utilizing the library pathlib is generated by Claude Code (Gemini).

        # Gemini added this line of code to create config.json in the user's Appdata/Local/QuickType
        self.app_data_path = Path(os.environ.get('LOCALAPPDATA', '.')) / 'QuickType' / 'config.json'

        # Gemini added an if statement to add interactability with the user's directory.
        if not os.path.exists(self.app_data_path):
            self.app_data_path.parent.mkdir(parents=True, exist_ok=True)
            with open(self.app_data_path, "w", encoding='utf-8') as file:
                # Gemini added the 'indent=4' at the end to add indents - something I did not know before
                json.dump({"trigger_character": ":", "shortcuts": {}}, file, indent=4)

        self.trigger_character = ":"
        self.shortcuts = {}
        self.load()

    def load(self):
        with open(self.app_data_path, "r", encoding='utf-8') as file:
            data = json.load(file)
            self.trigger_character = data.get("trigger_character", ":")
            self.shortcuts = data.get("shortcuts", {})
